xn__Ghi_Ch____b9a8609v23xb.onSubmit:
(async () => {
  try {
    // Lấy dữ liệu dòng vừa được chỉnh sửa
    const row = Kiem_Ke_Cong_Cu.triggeredRow; 

    // Nếu row không tồn tại, lấy dòng đang được chọn
    const targetRow = row || Kiem_Ke_Cong_Cu.selectedRow;

    if (!targetRow) {
      showAlert("⚠️ Không tìm thấy dòng dữ liệu!", "warning");
      return;
    }

    // Thực hiện Update vào DB
    await Action_Luu_Kiem_Ke_Tool.run({
        code: targetRow["Mã vật liệu / 物料编码"],
        qty: Number(targetRow["Kiểm Kê Thực Tế / 本月实际盘点"]),
        reason: targetRow["Nguyên Nhân Chênh Lệch / 差异原因"] ?? '',
        notes: targetRow["Ghi Chú / 备注"] ?? ''
    });

    // ÉP BẢNG CẬP NHẬT (Phần quan trọng để diệt con số 888)
    // 1. Chạy lại Query lấy dữ liệu gốc
    const newData = await Get_Inventory_Data.run();

    // 2. Ép bảng "quên" dữ liệu cũ và nạp lại dữ liệu mới toanh
    Kiem_Ke_Cong_Cu.setData(newData);

    showAlert("✅ Lưu thành công và đã cập nhật bảng!", "success");

  } catch (err) {
    showAlert("❌ Lỗi: " + err.message, "error");
  }
})()

